THEME_LABELS = {
    "dark": "Dark（内置深色）",
    "light": "Light（内置浅色）",
    "ocean": "Ocean（海蓝）",
    "forest": "Forest（森林绿）",
    "rose": "Rose（玫瑰粉）",
    "nord": "Nord（北欧）",
    "mono": "Mono（极简灰）",
    "dracula": "Dracula（德古拉）",
}

def themes_dir() -> Path:
    return Path.home() / ".pi" / "agent" / "themes"

def ensure_builtin_themes() -> list[str]:
    d = themes_dir()
    d.mkdir(parents=True, exist_ok=True)
    written = []
    for name, data in BUILTIN_THEMES.items():
        path = d / f"{name}.json"
        path.write_text(json.dumps(data, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
        written.append(name)
    return written

def list_theme_choices() -> list[tuple[str, str]]:
    # built-in + custom files
    ensure_builtin_themes()
    items = [("dark", THEME_LABELS["dark"]), ("light", THEME_LABELS["light"])]
    for name, label in THEME_LABELS.items():
        if name in ("dark", "light"):
            continue
        items.append((name, label))
    # extra user themes
    for p in sorted(themes_dir().glob("*.json")):
        n = p.stem
        if n not in THEME_LABELS and n not in ("dark", "light"):
            items.append((n, n))
    return items
